package main

import (
	"context"
	"fmt"
	"time"
)

// SumUntilCancelled adds integers 1, 2, 3, ... in a loop.
// Every 1000 iterations, it yields briefly and checks if ctx is cancelled.
// Returns the partial sum and the cancellation error (or nil if never cancelled).
func SumUntilCancelled(ctx context.Context) (int64, error) {
	var sum int64
	var i int64 = 1

	for {
		sum += i
		i++

		// Check for cancellation every 1000 iterations. The tiny
		// Sleep matters on the Go Playground sandbox, whose virtual
		// clock doesn't advance during pure CPU loops — without it,
		// context.WithTimeout would never fire here and the program
		// would hit the playground's 5 s hard limit. On real Go it's
		// negligible.
		if i%[[SLOT period]] == 0 {
			time.Sleep(time.Microsecond)
			if err := [[SLOT cause_fn]](ctx); err != nil {
				return sum, err
			}
		}
	}
}

func main() {
	// Create a context that cancels after 100 milliseconds
	ctx, cancel := [[SLOT timeout_fn]]([[SLOT bg_fn]](), 100*time.Millisecond)
	[[SLOT defer_kw]] cancel()

	sum, err := SumUntilCancelled(ctx)
	if err != nil {
		fmt.Println("Cancelled! Partial sum:", sum)
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Completed without cancellation. Sum:", sum)
	}
}
